"""matplotlib.path — Path stubs."""

import numpy as _np


class Path:
    """Stub matplotlib Path."""

    STOP = 0
    MOVETO = 1
    LINETO = 2
    CURVE3 = 3
    CURVE4 = 4
    CLOSEPOLY = 79

    def __init__(self, vertices, codes=None, _interpolation_steps=1,
                 closed=False, readonly=False):
        self.vertices = _np.asarray(vertices)
        self.codes = codes
        self._interpolation_steps = _interpolation_steps

    @staticmethod
    def unit_circle():
        t = _np.linspace(0, 2 * _np.pi, 64)
        verts = _np.column_stack([_np.cos(t), _np.sin(t)])
        return Path(verts)

    @staticmethod
    def unit_rectangle():
        return Path([(0, 0), (1, 0), (1, 1), (0, 1), (0, 0)])

    @staticmethod
    def unit_regular_polygon(numVertices):
        t = _np.linspace(0, 2 * _np.pi, numVertices + 1)
        verts = _np.column_stack([_np.cos(t), _np.sin(t)])
        return Path(verts)

    @staticmethod
    def unit_circle_righthalf():
        t = _np.linspace(-_np.pi/2, _np.pi/2, 32)
        verts = _np.column_stack([_np.cos(t), _np.sin(t)])
        return Path(verts)

    def contains_point(self, point, transform=None, radius=0.0):
        return False

    def contains_points(self, points, transform=None, radius=0.0):
        return _np.zeros(len(points), dtype=bool)

    def intersects_path(self, other, filled=True):
        return False

    def get_extents(self, transform=None):
        return _np.array([self.vertices[:, 0].min(), self.vertices[:, 1].min(),
                          self.vertices[:, 0].max(), self.vertices[:, 1].max()])

    def transformed(self, transform):
        return self

    def __len__(self):
        return len(self.vertices)
